import React from "react";
import { useState } from "react";

function App() {
  let [formData, setFormData] = useState({});
  let [arr, setArr] = useState([]);

  let handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  let handleSubmit = (e) => {
    e.preventDefault();
    setArr([...arr, formData]);
  
  };

  console.log(arr);

  return (
    <div>
      <input
        onChange={handleChange}
        name="username"
        type="text"
        placeholder="Enter name.."
      />{" "}
      <br />
      <input
        onChange={handleChange}
        name="useremail"
        type="email"
        placeholder="Enter email.."
      />{" "}
      <br />
      <button onClick={handleSubmit}>ADD</button>
      <table border={1}>
        <thead>
          <tr>
            <th>Name</th>
            <th>Email</th>
          </tr>
        </thead>

        <tbody>
          {arr.map((e, i) => {
            return (
              <tr key={i}>
                <td>{e.username}</td>
                <td>{e.useremail}</td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

export default App;

